317:     private static final String SHA512TRUNCATED = "SHA512/2";
318: 
319:     private static String[] tokenizeTransformation(String transformation)
320:             throws NoSuchAlgorithmException {
321:         if (transformation == null) {
322:             throw new NoSuchAlgorithmException("No transformation given");
323:         }
324:         /*
325:          * array containing the components of a cipher transformation:
326:          *
327:          * index 0: algorithm component (e.g., AES)
328:          * index 1: feedback component (e.g., CFB)
329:          * index 2: padding component (e.g., PKCS5Padding)
330:          */
331:         String[] parts = { "", "", "" };
332: 
333:         // check if the transformation contains algorithms with "/" in their
334:         // name which can cause the parsing logic to go wrong
335:         int sha512Idx = transformation.toUpperCase(Locale.ENGLISH)
336:                 .indexOf(SHA512TRUNCATED);
337:         int startIdx = (sha512Idx == -1 ? 0 :
338:                 sha512Idx + SHA512TRUNCATED.length());
339:         int endIdx = transformation.indexOf('/', startIdx);
340:         if (endIdx == -1) {
341:             // algorithm
342:             parts[0] = transformation.trim();
343:         } else {
344:             // algorithm/mode/padding
345:             parts[0] = transformation.substring(0, endIdx).trim();
346:             startIdx = endIdx+1;
347:             endIdx = transformation.indexOf('/', startIdx);
348:             if (endIdx == -1) {
349:                 throw new NoSuchAlgorithmException("Invalid transformation"
350:                             + " format:" + transformation);
351:             }
352:             parts[1] = transformation.substring(startIdx, endIdx).trim();
353:             parts[2] = transformation.substring(endIdx+1).trim();
354:         }
355:         if (parts[0].isEmpty()) {
356:             throw new NoSuchAlgorithmException("Invalid transformation: " +
357:                                    "algorithm not specified-"
358:                                    + transformation);
359:         }
360:         return parts;
361:     }
