240:         static void loadInclude(String propFile) {
241:             String expPropFile = PropertyExpander.expandNonStrict(propFile);
242:             if (sdebug != null) {
243:                 sdebug.println("processing include: '" + propFile + "'" +
244:                         (propFile.equals(expPropFile) ? "" :
245:                                 " (expanded to '" + expPropFile + "')"));
246:             }
247:             try {
248:                 Path path = Path.of(expPropFile);
249:                 if (!path.isAbsolute()) {
250:                     if (currentPath == null) {
251:                         throw new InternalError("Cannot resolve '" +
252:                                 expPropFile + "' relative path when included " +
253:                                 "from a non-regular properties file " +
254:                                 "(e.g. HTTP served file)");
255:                     }
256:                     path = currentPath.resolveSibling(path);
257:                 }
258:                 loadFromPath(path, LoadingMode.APPEND);
259:             } catch (IOException | InvalidPathException e) {
260:                 throw new InternalError("Unable to include '" + expPropFile +
261:                         "'", e);
262:             }
263:         }
