265:         private static void loadFromPath(Path path, LoadingMode mode)
266:                 throws IOException {
267:             boolean isRegularFile = Files.isRegularFile(path);
268:             if (isRegularFile) {
269:                 path = path.toRealPath();
270:             } else if (Files.isDirectory(path)) {
271:                 throw new IOException("Is a directory");
272:             } else {
273:                 path = path.toAbsolutePath();
274:             }
275:             if (activePaths.contains(path)) {
276:                 throw new InternalError("Cyclic include of '" + path + "'");
277:             }
278:             try (InputStream is = Files.newInputStream(path)) {
279:                 reset(mode);
280:                 Path previousPath = currentPath;
281:                 currentPath = isRegularFile ? path : null;
282:                 activePaths.add(path);
283:                 try {
284:                     debugLoad(true, path);
285:                     props.load(is);
286:                     debugLoad(false, path);
287:                 } finally {
288:                     activePaths.remove(path);
289:                     currentPath = previousPath;
290:                 }
291:             }
292:         }
