342:     /**
343:      * Looks up providers, and returns the property (and its associated
344:      * provider) mapping the key, if any.
345:      * The order in which the providers are looked up is the
346:      * provider-preference order, as specified in the security
347:      * properties file.
348:      */
349:     private static ProviderProperty getProviderProperty(String key) {
350: 
351:         List<Provider> providers = Providers.getProviderList().providers();
352:         for (int i = 0; i < providers.size(); i++) {
353: 
354:             String matchKey;
355:             Provider prov = providers.get(i);
356:             String prop = prov.getProperty(key);
357: 
358:             if (prop == null) {
359:                 // Is there a match if we do a case-insensitive property name
360:                 // comparison? Let's try ...
361:                 for (Enumeration<Object> e = prov.keys();
362:                                 e.hasMoreElements(); ) {
363:                     matchKey = (String)e.nextElement();
364:                     if (key.equalsIgnoreCase(matchKey)) {
365:                         prop = prov.getProperty(matchKey);
366:                         break;
367:                     }
368:                 }
369:             }
370: 
371:             if (prop != null) {
372:                 ProviderProperty newEntry = new ProviderProperty();
373:                 newEntry.className = prop;
374:                 newEntry.provider = prov;
375:                 return newEntry;
376:             }
