539:             throws NoSuchAlgorithmException, NoSuchPaddingException
540:     {
541:         if ((transformation == null) || transformation.isEmpty()) {
542:             throw new NoSuchAlgorithmException("Null or empty transformation");
543:         }
544:         List<Transform> transforms = getTransforms(transformation);
545:         List<ServiceId> cipherServices = new ArrayList<>(transforms.size());
546:         for (Transform transform : transforms) {
547:             cipherServices.add(new ServiceId("Cipher", transform.transform));
548:         }
549:         // make sure there is at least one service from a signed provider
550:         // and that it can use the specified mode and padding
551:         Iterator<Service> t = GetInstance.getServices(cipherServices);
552:         Exception failure = null;
553:         while (t.hasNext()) {
554:             Service s = t.next();
555:             if (JceSecurity.canUseProvider(s.getProvider()) == false) {
556:                 continue;
557:             }
558:             Transform tr = getTransform(s, transforms);
559:             if (tr == null) {
560:                 // should never happen
561:                 continue;
562:             }
563:             int canuse = tr.supportsModePadding(s);
564:             if (canuse == S_NO) {
565:                 // does not support mode or padding we need, ignore
566:                 continue;
567:             }
568:             // S_YES, S_MAYBE
569:             // even when mode and padding are both supported, they
570:             // may not be used together, try out and see if it works
571:             try {
572:                 CipherSpi spi = (CipherSpi)s.newInstance(null);
573:                 tr.setModePadding(spi);
574:                 // specify null instead of spi for delayed provider selection
575:                 return new Cipher(null, s, t, transformation, transforms);
576:             } catch (Exception e) {
577:                 failure = e;
578:             }
579:         }
580:         throw new NoSuchAlgorithmException
581:             ("Cannot find any provider supporting " + transformation, failure);
